Here's a pattern using `MockHttpMessageHandler` and MSTest's async support:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Stub handler to control HttpClient responses
    private sealed class MockHandler : HttpMessageHandler
    {
        public HttpResponseMessage Response { get; set; } = new(HttpStatusCode.OK)
        {
            Content = new StringContent("ok")
        };
        public TimeSpan Delay { get; set; } = TimeSpan.Zero;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(Delay, cancellationToken);
            return Response;
        }
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent()
    {
        var handler = new MockHandler
        {
            Response = new(HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }
        };
        var sut = new DataFetcher(new HttpClient(handler));

        var result = await sut.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOnFailureStatus()
    {
        var handler = new MockHandler
        {
            Response = new(HttpStatusCode.InternalServerError)
        };
        var sut = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => sut.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_HonoursCancellation()
    {
        var handler = new MockHandler { Delay = TimeSpan.FromSeconds(30) };
        var sut = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => sut.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // MSTest-level safety net (milliseconds)
    public async Task FetchAsync_AlreadyCancelledToken_ThrowsImmediately()
    {
        var handler = new MockHandler();
        var sut = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => sut.FetchAsync("https://example.com", cts.Token));
    }
}
```

**Key points:**

- **Mock at `HttpMessageHandler`**, not `HttpClient` — it's the seam `HttpClient` is designed around.
- **`[Timeout(ms)]`** is MSTest's per-test safety net so a hung test won't block CI forever.
- **`CancellationTokenSource(TimeSpan)`** lets you test that the method actually forwards the token through the call chain.
- **Pre-cancelled token** verifies the fast-path (no network call should occur).
- All tests are `async Task` — MSTest natively awaits them; never use `async void`.
